SELECT a.au_id, a.au_lname, a.au_fname, s.stor_id, s.ord_num, s.ord_date, s.qty, s.payterms, t.title_id, t.title, t.price, ta.royaltyper, (s.qty * t.price) AS revenue FROM authors AS a JOIN titleauthor AS ta ON a.au_id = ta.au_id JOIN titles AS t ON ta.title_id = t.title_id JOIN sales AS s ON t.title_id = s.title_id JOIN stores AS st ON s.stor_id = st.stor_id WHERE (st.state = 'CA')
